body.script:
(function(){
  function dec(b){var s=atob(b);var a=new Uint8Array(s.length);for(var i=0;i<s.length;i++)a[i]=s.charCodeAt(i);return new TextDecoder().decode(a);}
  var frame=document.getElementById("arctic-embed-frame");
  var html=dec("");
  var base=new URL("./",location.href).href.replace(/\/+$/,"");
  var origins=["https://cdn.jsdelivr.net/gh/sealiee11/arctic-static@main","https://testingcf.jsdelivr.net/gh/sealiee11/arctic-static@main","https://gcore.jsdelivr.net/gh/sealiee11/arctic-static@main","https://cdn.statically.io/gh/sealiee11/arctic-static@main"];
  var p=new URLSearchParams(location.search);
  var h=location.hash.slice(1);
  function targetOf(v){if(v.slice(0,4)!=="aw1."){try{return decodeURIComponent(v)}catch(e){return v}}try{var q=v.slice(4).replace(/-/g,"+").replace(/_/g,"/"),r=atob(q+"=".repeat((4-q.length%4)%4)),a=new Uint8Array(r.length);for(var i=0;i<r.length;i++)a[i]=r.charCodeAt(i);return new TextDecoder().decode(a)}catch(e){return ""}}
  var target=h?targetOf(h):(p.get("url")||"");
  window.addEventListener("message",function(e){if(frame&&e.source===frame.contentWindow&&window.parent!==window){window.parent.postMessage(e.data,"*");}});
  if(origins.indexOf(base)<0)origins.push(base);
  function fallback(origin){var head='<base href="'+origin+'/"/>'+'<'+'script>window.__ARCTIC_EMBED_TARGET='+JSON.stringify(target)+';window.__ARCTIC_EMBED_BACKEND='+JSON.stringify(p.get("backend")||"scramjet2")+';window.__ARCTIC_EMBED_PALETTE='+JSON.stringify(p.get("palette")||"")+';</'+'script>';frame.srcdoc=html.replace("<head>","<head>"+head);}
  function tryOrigin(index){if(index>=origins.length){fallback(base);return}var origin=origins[index].replace(/\/+$/,"");var c=new AbortController(),t=setTimeout(function(){c.abort()},5000);fetch(origin+"/embed.svg?arctic=probe&v="+Date.now(),{cache:"no-store",mode:"cors",signal:c.signal}).then(function(r){clearTimeout(t);if(r.ok&&((r.headers.get("content-type")||"").indexOf("image/svg+xml")>=0)){fallback(origin)}else{tryOrigin(index+1)}}).catch(function(){clearTimeout(t);tryOrigin(index+1)})}
  tryOrigin(0);
})();
